using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Shared state for note-taking ---
var notebook = new Notebook();

// --- Build the IChatClient through MEAI ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var searchTool = new WebSearchTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchTool.SearchAsync),
    AIFunctionFactory.Create(searchTool.FetchPageAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Build the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your goal is to thoroughly research the topic
        the user provides by following these steps:

        1. Use web_search to find relevant information on the topic.
        2. Use fetch_page on promising URLs to get detailed content.
        3. Use add_note to record key findings (take at least 3 notes).
        4. After gathering enough information, use get_notes to review your notes,
           then produce a well-structured summary with key points and sources.

        Be thorough and cite your sources. Always finish with a final summary.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get the research topic ---
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");
Console.WriteLine(new string('─', 60));

// --- Run the agent ---
var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a detailed summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("Research complete.");

// ──────────────────────────────────────────────────────────
// Tool implementations
// ──────────────────────────────────────────────────────────

sealed class WebSearchTool
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Searches the web for the given query and returns a list of result URLs and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

        try
        {
            var html = await _http.GetStringAsync(url);
            return ExtractSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetches the text content of a web page at the given URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url)
    {
        try
        {
            var html = await _http.GetStringAsync(url);
            var text = StripHtml(html);
            return text.Length > 4000
                ? string.Concat(text.AsSpan(0, 4000), "\n[Truncated]")
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ExtractSearchResults(string html)
    {
        var sb = new StringBuilder();
        var matches = LinkRegex().Matches(html);
        var count = 0;

        foreach (Match match in matches)
        {
            var href = match.Groups[1].Value;
            if (href.StartsWith("http", StringComparison.Ordinal)
                && !href.Contains("duckduckgo", StringComparison.Ordinal))
            {
                sb.AppendLine($"- {href}");
                if (++count >= 8) break;
            }
        }

        if (count == 0)
            return "No search results found.";

        var plainText = StripHtml(html);
        if (plainText.Length > 3000)
            plainText = plainText[..3000];

        return $"Search results:\n{sb}\nSnippets:\n{plainText}";
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = WhitespaceRegex().Replace(text, " ");
        return text.Trim();
    }

    [GeneratedRegex(@"href=""([^""]+)""", RegexOptions.IgnoreCase)]
    private static partial Regex LinkRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

sealed class Notebook
{
    private readonly List<(string Title, string Body)> _notes = [];

    [Description("Saves a research note with a title and body for later reference.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        _notes.Add((title, body));
        Console.WriteLine($"  📝 Note saved: \"{title}\" ({_notes.Count} total)");
        return $"Note saved: '{title}' (total notes: {_notes.Count})";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"## Note {i + 1}: {_notes[i].Title}");
            sb.AppendLine(_notes[i].Body);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

