 using System.ComponentModel;
 using System.Text;
 using System.Text.RegularExpressions;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
     ?? "gpt-4o-mini-2024-07-18";

 // --- Shared state for note-taking ---
 var notebook = new Notebook();

 // --- Build the IChatClient through MEAI ---
 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // --- Define tools ---
 var searchTool = new WebSearchTool();

 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(searchTool.SearchAsync),
     AIFunctionFactory.Create(searchTool.FetchPageAsync),
     AIFunctionFactory.Create(notebook.AddNote),
     AIFunctionFactory.Create(notebook.GetNotes),
 };

 // --- Build the agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Your goal is to thoroughly research the topic
         the user provides by following these steps:

         1. Use web_search to find relevant information on the topic.
         2. Use fetch_page on promising URLs to get detailed content.
         3. Use add_note to record key findings (take at least 3 notes).
         4. After gathering enough information, use get_notes to review your notes,
            then produce a well-structured summary with key points and sources.

         Be thorough and cite your sources. Always finish with a final summary.
         """,
     name: "ResearchAgent",
     description: "An agent that researches topics by searching the web and taking notes.",
     tools: tools);

 // --- Get the research topic ---
 Console.Write("Enter a topic to research: ");
 var topic = Console.ReadLine()?.Trim();
 if (string.IsNullOrEmpty(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine($"\nResearching: {topic}\n");
 Console.WriteLine(new string('─', 60));

 // --- Run the agent ---
 var session = await agent.CreateSessionAsync();
 var runOptions = new ChatClientAgentRunOptions
 {
     ChatOptions = new ChatOptions
     {
         Temperature = 0f,
         MaxOutputTokens = 2048,
     },
 };

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a detailed summary: {topic}",
     session,
     runOptions))
 {
     Console.Write(update.Text);
 }

 Console.WriteLine();
 Console.WriteLine(new string('─', 60));
 Console.WriteLine("Research complete.");

